// Extract reply from Groq or Gemini response
const groqData = $('Call Groq AI').first()?.json;
const geminiData = $('Call Gemini (Fallback)').first()?.json;

let rawReply = '';
if (groqData?.choices?.[0]?.message?.content) {
  rawReply = groqData.choices[0].message.content;
} else if (geminiData?.candidates?.[0]?.content?.parts?.[0]?.text) {
  rawReply = geminiData.candidates[0].content.parts[0].text;
} else {
  rawReply = 'Thanks for reaching out! Please call us at 727-265-1038 for immediate assistance.';
}

// Extract LEAD_DATA if present
const leadMatch = rawReply.match(/LEAD_DATA:(\{.*\})/);
let leadData = null;
if (leadMatch) {
  try { leadData = JSON.parse(leadMatch[1]); } catch(e) {}
}

// Clean reply
const reply = rawReply.replace(/LEAD_DATA:\{.*\}/, '').trim();

return [{ json: { reply, leadData } }];

// Score the chatbot lead
const lead = $json.leadData;
let score = 0;

const tl = (lead.timeline || '').toLowerCase();
if (tl.includes('asap')) score += 40;
else if (tl.includes('month') && !tl.includes('3')) score += 25;
else if (tl.includes('1-3')) score += 10;

const svc = (lead.service || '').toLowerCase();
if (svc.includes('hurricane') || svc.includes('impact')) score += 30;
else if (svc.includes('full') || svc.includes('whole')) score += 30;
else if (svc.includes('energy')) score += 20;
else if (svc.includes('commercial')) score += 25;
else if (svc.includes('single')) score += 10;
else if (svc.includes('repair')) score += 5;
else score += 15;

if (lead.phone?.length > 7) score += 15;
if (lead.email?.includes('@')) score += 10;
score += 5; // chatbot bonus

const rating = score >= 70 ? 'HOT' : score >= 40 ? 'WARM' : 'COLD';
const timestamp = new Date().toLocaleString('en-US', { timeZone: 'America/New_York' });

return [{ json: { ...lead, score, rating, timestamp, source: 'chatbot' } }];
